questionvariables.text:
/* ===== Parameter set selection ===== */
set: rand(3)+1;

/* ===== Given values ===== */
N_val: if set=1 then 200 else if set=2 then 500 else 300;
r_cm:  if set=1 then 2   else if set=2 then 1.5 else 3;
ell_cm: if set=1 then 20  else if set=2 then 10  else 30;
I_val: if set=1 then 1.5  else if set=2 then 0.8 else 2.0;

/* ===== Derived values ===== */
mu0: 4*%pi/10^7;
r_val: r_cm/100;
ell_val: ell_cm/100;
A_val: float(%pi*r_val^2);
L_val: float(mu0*N_val^2*A_val/ell_val);
W_val: float(0.5*L_val*I_val^2);

/* Display-friendly */
L_mH: float(L_val*1000);
W_mJ: float(W_val*1000);

/* ===== Common-error references ===== */
L_wrong_no_N2: float(mu0*N_val*A_val/ell_val);
L_wrong_swap_ell_A: float(mu0*N_val^2*ell_val/A_val);
L_wrong_no_pi: float(mu0*N_val^2*r_val^2/ell_val);

/* ===== Teacher answers ===== */
ta1: float(L_val*1000);  /* L in mH */
ta2: float(W_val*1000);  /* W in mJ */

/* Part (c) MCQ: Debug — student computed wrong L, identify error */
/* L_wrong_no_N2 means they used N instead of N^2 */
ta3: [[1, true, "They used N instead of N² — the correct formula is L = μ₀N²A/ℓ, not L = μ₀NA/ℓ"],
      [2, false, "They forgot to convert cm to m in the radius"],
      [3, false, "They swapped the area and length — using L = μ₀N²ℓ/A"],
      [4, false, "They forgot to include μ₀ in the formula"]];
ta3_correct: 1;

/* Part (d) MCQ: If current doubles, energy factor */
ta4: [[1, false, "The energy doubles (W ∝ I)"],
      [2, true, "The energy quadruples (W ∝ I²)"],
      [3, false, "The energy stays the same (L is independent of I)"],
      [4, false, "The energy increases by a factor of 8 (W ∝ I³)"]];
ta4_correct: 2;

feedbackvariables.text:
sa1_float: float(ans1);
ref1_float: float(ta1);
/* Order-of-magnitude check */
prt1_oom_ok: if (abs(ref1_float) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and (abs(sa1_float/ref1_float - 10) < 1.5 or abs(sa1_float/ref1_float - 0.1) < 0.015)) then true else false;
/* Common error checks */
prt1_forgot_N2: if (abs(L_wrong_no_N2*1000) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and abs(sa1_float/(L_wrong_no_N2*1000) - 1) < 0.05) then true else false;
prt1_swap_ell_A: if (abs(L_wrong_swap_ell_A*1000) > 1.0e-30 and abs(sa1_float) > 1.0e-30 and abs(sa1_float/(L_wrong_swap_ell_A*1000) - 1) < 0.05) then true else false;

sa2_float: float(ans2);
ref2_float: float(ta2);
/* Order-of-magnitude check */
prt2_oom_ok: if (abs(ref2_float) > 1.0e-30 and abs(sa2_float) > 1.0e-30 and (abs(sa2_float/ref2_float - 10) < 1.5 or abs(sa2_float/ref2_float - 0.1) < 0.015)) then true else false;
